#!/bin/bash
# Uninstall script for Vagrant
# Generated by IntuneBrew

# Exit on error
set -e

echo "Uninstalling Vagrant..."

# Check if running as root
if [ "$EUID" -ne 0 ]; then
  echo "Please run as root"
  exit 1
fi

# Kill application process if running
echo "Stopping Vagrant if running..."
pkill -f "Vagrant" 2>/dev/null || true

# Remove $HOME/.vagrant.d
echo "Removing $HOME/.vagrant.d..."
if [ -d "$HOME/.vagrant.d" ]; then
    rm -rf "$HOME/.vagrant.d" 2>/dev/null || true
elif [ -f "$HOME/.vagrant.d" ]; then
    rm -f "$HOME/.vagrant.d" 2>/dev/null || true
fi

echo "Uninstallation complete!"
exit 0
